  ('elementary-8b44517b-moex-00389', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依實務見解，下列關於刑法第134條不真正瀆職罪之敘述，何者錯誤？', '["本條之行為主體以具有公務員身分者為限", "本條之實行行為須與行為人職務具有關連性", "本條為故意犯，但不以行為人有直接故意為限，未必故意亦包括在內", "本條為公務員瀆職罪之概括規定，故為總則加重規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00390', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者非民法物權之原則？', '["物權相對性", "物權法定主義", "公示原則", "物權優先效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00391', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過某些措施的採行，刺激景氣復甦，帶動經濟成長。下列何者無法 達成刺激景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "取消補貼政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00392', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '若世界僅由甲、乙兩國組成，且甲國生產所有商品的效率皆比乙國的水準高。若以機會成本的觀點而言， 下列有關甲、乙兩國生產及貿易的敘述，何者正確？', '["甲國生產所有商品均具絕對利益", "乙國向甲國進口所有產品最有利", "甲國生產所有商品的機會成本低於乙國", "若兩國進行分工，甲、乙兩國的生產可能線會內縮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00393', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '大學剛畢業的小湘有三個工作機會與繼續升學的道路可選擇，一是月薪2萬5千元的家教老師；另一是 月薪2萬8千元的房屋仲介；以及月薪3萬元的法務助理；若選擇不就業，繼續進入研究所碩士班就讀， 學雜費兩年共需20萬元。依上述資料判斷，在不考慮其他條件的情況下，針對小湘大學畢業後兩年間做 選擇的機會成本之敘述，下列何者正確？', '["若當家教老師，機會成本為67萬2千元", "若選擇當房屋仲介，外顯成本為72萬元", "若選擇就學，外顯成本為72萬元", "若選擇就學，機會成本為92萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00394', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '從塑化劑事件到毒澱粉，食安危機連環爆，連許多老店與大公司的知名產品都因使用有害人體健康的原 料，使消費者人人自危，深怕吃下肚的是黑心商品。許多產品銷售成績一落千丈，對加工食品業的業績 有負面影響。上述事件使消費者對加工食品需求的影響，下列何者正確？', '["預期加工食品價格會下跌，導致其需求曲線左移", "消費者對加工食品的偏好降低，導致其需求曲線左移", "加工食品的互補品價格下跌，導致加工食品的需求曲線右移", "天然食材製品的價格上漲，導致加工食品的需求曲線右移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00395', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '下列何種情況會使目前國產豬肉需求曲線往左移？', '["人口減少", "豬肉價格下降", "出現狂牛症疑慮", "行政院環境保護署嚴格取締養豬場對環境的污染"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00396', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '甲、乙兩國均為已開發國家，甲國某年兩性同酬日為2個月又5天，乙國則為2個月又27天，顯示相較 於甲國，乙國受僱員工中女性要花費更多工作時間才能與男性同酬。根據上述，下列何種敘述或推測最 為可能？', '["乙國的性別職業隔離現象較甲國嚴重", "甲國制定的女性勞動政策較乙國友善", "兩國男性受高等教育的比例較女性多", "甲國的受僱者人均國民所得較乙國高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
